import numpy as np

def initializeCentroids(dataset, k):
 # Initialize centroids randomly
 return np.random.choice(dataset, size=k, replace=False)

def findClosestCentroid(dataPoint, centroids):
 # Find closest centroid to data point
 distances = np.linalg.norm(dataPoint - centroids, axis=1)
 return np.argmin(distances)

def updateCentroids(dataset, clusterAssignments, k):
 # Update centroids as mean of assigned data points
 centroids = np.zeros((k, dataset.shape[1]))
 for i in range(k):
 clusterPoints = dataset[clusterAssignments == i]
 centroids[i] = np.mean(clusterPoints, axis=0)
 return centroids

def kMeans(dataset, k):
 centroids = initializeCentroids(dataset, k)
 clusterAssignments = np.zeros(dataset.shape[0], dtype=int)

 while True:
 # Assignment step
 for i, dataPoint in enumerate(dataset):
 closestCentroid = findClosestCentroid(dataPoint, centroids)
 clusterAssignments[i] = closestCentroid

 # Update step
 newCentroids = updateCentroids(dataset, clusterAssignments, k)

 # Check for convergence
 if np.all(centroids == newCentroids):
 break

 centroids = newCentroids

 return clusterAssignments, centroids

